<section class="card" data-section-index="2" id="section-clinical"><?php $done = !empty($sectionStatuses['clinical']); ?><div class="card-head"><div><h3>Clinical Findings</h3></div><span class="badge <?php echo $done ? 'done' : 'missing'; ?>"><?php echo $done ? 'Completed' : 'Incomplete'; ?></span></div><div class="grid"><div class="field"><label>Clinical Findings Present</label><select name="result_clinical_findings"><option value="">Select</option><option value="Yes" <?php echo old('result_clinical_findings', $clinicalFindings->result_clinical_findings ?? '') === 'Yes' ? 'selected' : ''; ?>>Yes</option><option value="No" <?php echo old('result_clinical_findings', $clinicalFindings->result_clinical_findings ?? '') === 'No' ? 'selected' : ''; ?>>No</option></select></div><div class="field full"><label>Describe current health effects</label><textarea name="elaboration"><?php echo $esc(old('elaboration', $clinicalFindings->elaboration ?? '')); ?></textarea></div></div></section>
<section class="card" data-section-index="3" id="section-physical"><?php $done = !empty($sectionStatuses['physical']); ?><div class="card-head"><div><h3>Physical Examination</h3></div><span class="badge <?php echo $done ? 'done' : 'missing'; ?>"><?php echo $done ? 'Completed' : 'Incomplete'; ?></span></div><div class="grid-3"><div class="field"><label>Weight (kg)</label><input type="number" step="0.01" name="weight" value="<?php echo $esc(old('weight', $physicalExam->weight ?? '')); ?>"></div><div class="field"><label>Height (cm)</label><input type="number" step="0.01" name="height" value="<?php echo $esc(old('height', $physicalExam->height ?? '')); ?>"></div><div class="field"><label>BMI</label><input type="number" step="0.01" name="BMI" value="<?php echo $esc(old('BMI', $physicalExam->BMI ?? '')); ?>"></div><div class="field"><label>Blood Pressure Systolic</label><input type="number" name="bp_systolic" value="<?php echo $esc(old('bp_systolic', $physicalExam->bp_systolic ?? '')); ?>"></div><div class="field"><label>Blood Pressure Diastolic</label><input type="number" name="bp_distolic" value="<?php echo $esc(old('bp_distolic', $physicalExam->bp_distolic ?? '')); ?>"></div><div class="field"><label>Pulse Rate</label><input type="number" name="pulse_rate" value="<?php echo $esc(old('pulse_rate', $physicalExam->pulse_rate ?? '')); ?>"></div><div class="field"><label>Respiratory Rate</label><input type="number" name="respiratory_rate" value="<?php echo $esc(old('respiratory_rate', $physicalExam->respiratory_rate ?? '')); ?>"></div><div class="field full"><label>General Appearances</label><textarea name="general_appearances"><?php echo $esc(old('general_appearances', $physicalExam->general_appearances ?? '')); ?></textarea></div></div><div class="system-grid" style="margin-top:14px;"><?php foreach($physicalFields as $field): ?><div class="field"><label><?php echo $esc($field['label']); ?></label><?php if($field['type'] === 'select'): ?><select name="<?php echo $esc($field['name']); ?>"><option value="">Select</option><?php foreach($field['options'] as $option): ?><option value="<?php echo $esc($option); ?>" <?php echo old($field['name'], $physicalExam->{$field['name']} ?? '') === $option ? 'selected' : ''; ?>><?php echo $esc($option); ?></option><?php endforeach; ?></select><?php else: ?><input type="text" name="<?php echo $esc($field['name']); ?>" value="<?php echo $esc(old($field['name'], $physicalExam->{$field['name']} ?? '')); ?>"><?php endif; ?></div><?php endforeach; ?><div class="field" style="grid-column:1/-1;"><label>Others</label><textarea name="others"><?php echo $esc(old('others', $physicalExam->others ?? '')); ?></textarea></div></div></section>
