 ? 'checked' : ''; ?>></td><td class="text-cell"><textarea name="liver_comments"><?php echo $esc(old('liver_comments', $targetOrgan->liver_comments ?? '')); ?></textarea></td></tr><tr><th>Chest X-ray</th><td class="choice-cell"><input type="radio" name="chest_xray" value="Normal" <?php echo old('chest_xray', $targetOrgan->chest_xray ?? '') === 'Normal' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="chest_xray" value="Abnormal" <?php echo old('chest_xray', $targetOrgan->chest_xray ?? '') === 'Abnormal' ? 'checked' : ''; ?>></td><td class="text-cell"><textarea name="chest_comments"><?php echo $esc(old('chest_comments', $targetOrgan->chest_comments ?? '')); ?></textarea></td></tr><tr><th>Spirometry</th><td colspan="3" class="text-cell"><div class="grid-3"><div class="field"><label>FEV 1</label><input type="number" step="0.01" name="spirometry_FEV1" value="<?php echo $esc(old('spirometry_FEV1', $targetOrgan->spirometry_FEV1 ?? '')); ?>"></div><div class="field"><label>FVC</label><input type="number" step="0.01" name="spirometry_FVC" value="<?php echo $esc(old('spirometry_FVC', $targetOrgan->spirometry_FVC ?? '')); ?>"></div><div class="field"><label>FEV / FVC</label><input type="number" step="0.01" name="spirometry_FEV_FVC" value="<?php echo $esc(old('spirometry_FEV_FVC', $targetOrgan->spirometry_FEV_FVC ?? '')); ?>"></div></div><div class="field" style="margin-top:12px;"><label>Comments</label><textarea name="spirometry_comments"><?php echo $esc(old('spirometry_comments', $targetOrgan->spirometry_comments ?? '')); ?></textarea></div></td></tr></tbody></table></div></section>
<section class="card" data-section-index="5" id="section-biological"><?php $done = !empty($sectionStatuses['biological']); ?><div class="card-head"><div><h3>Biological Monitoring</h3></div><span class="badge <?php echo $done ? 'done' : 'missing'; ?>"><?php echo $done ? 'Completed' : 'Incomplete'; ?></span></div><div class="exam-table-wrap"><table class="exam-table" id="bioMonitoringTable"><thead><tr><th>Biological Exposure Indices / Determinants</th><th>Baseline</th><th>Annual</th><th class="choice-cell">Action</th></tr></thead><tbody><?php foreach ($bioRows as $bioRow): ?><tr class="bio-row"><td class="text-cell"><input type="text" class="bio-determinant" value="<?php echo $esc($bioRow['determinant']); ?>" placeholder="Determinant / test name"></td><td class="text-cell"><input type="text" class="bio-baseline" value="<?php echo $esc($bioRow['baseline']); ?>" placeholder="Baseline result"></td><td class="text-cell"><input type="text" class="bio-annual" value="<?php echo $esc($bioRow['annual']); ?>" placeholder="Annual result"></td><td class="choice-cell"><button type="button" class="small-btn bio-remove" style="padding:8px 12px;min-width:44px;">&#8855;</button></td></tr><?php endforeach; ?></tbody></table></div><div class="table-actions"><button type="button" class="small-btn" id="addBioRow">+ Add Biological Result</button></div></section><section class="card" data-section-index="6" id="section-respirator"><?php $done = !empty($sectionStatuses['respirator']); ?><div class="card-head"><div><h3>Fitness to Wear Respirator</h3></div><span class="badge <?php echo $done ? 'done' : 'missing'; ?>"><?php echo $done ? 'Completed' : 'Incomplete'; ?></span></div><div class="exam-table-wrap"><table class="exam-table"><thead><tr><th style="width:35%;">Conclusion on fitness to wear respirator</th><th class="choice-cell">Fit</th><th class="choice-cell">Not fit</th><th>Please justify</th></tr></thead><tbody><tr><th>Respirator fitness</th><td class="choice-cell"><input type="radio" name="fitness_result" value="Fit" <?php echo old('fitness_result', $fitnessRespirator->fitness_result ?? '') === 'Fit' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="fitness_result" value="Not fit" <?php echo old('fitness_result', $fitnessRespirator->fitness_result ?? '') === 'Not fit' ? 'checked' : ''; ?>></td><td class="text-cell"><textarea name="fitness_justification"><?php echo $esc(old('fitness_justification', $fitnessRespirator->fitness_justification ?? '')); ?></textarea></td></tr></tbody></table></div></section>
<section class="card" data-section-index="7" id="section-findings"><?php $done = !empty($sectionStatuses['findings']); ?><div class="card-head"><div><h3>MS Findings</h3></div><span class="badge <?php echo $done ? 'done' : 'missing'; ?>"><?php echo $done ? 'Completed' : 'Incomplete'; ?></span></div><div class="exam-table-wrap"><table class="exam-table"><thead><tr><th>MS Finding</th><th class="choice-cell">Yes</th><th class="choice-cell">No</th><th class="choice-cell">Work Related Yes</th><th class="choice-cell">Work Related No</th></tr></thead><tbody><tr><th>History of health effects due to chemical exposure [H]</th><td class="choice-cell"><input type="radio" name="history_of_health" value="Yes" <?php echo old('history_of_health', $msFindings->history_of_health ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="history_of_health" value="No" <?php echo old('history_of_health', $msFindings->history_of_health ?? '') === 'No' ? 'checked' : ''; ?>></td><td class="na-cell" colspan="2">Not applicable</td></tr><tr><th>Clinical findings [I]</th><td class="choice-cell"><input type="radio" name="clinical_findings" value="Yes" <?php echo old('clinical_findings', $msFindings->clinical_findings ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="clinical_findings" value="No" <?php echo old('clinical_findings', $msFindings->clinical_findings ?? '') === 'No' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="CF_work_related" value="Yes" <?php echo old('CF_work_related', $msFindings->CF_work_related ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="CF_work_related" value="No" <?php echo old('CF_work_related', $msFindings->CF_work_related ?? '') === 'No' ? 'checked' : ''; ?>></td></tr><tr><th>Target organ function test results [J]</th><td class="choice-cell"><input type="radio" name="target_organ" value="Yes" <?php echo old('target_organ', $msFindings->target_organ ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="target_organ" value="No" <?php echo old('target_organ', $msFindings->target_organ ?? '') === 'No' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="TO_work_related" value="Yes" <?php echo old('TO_work_related', $msFindings->TO_work_related ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="TO_work_related" value="No" <?php echo old('TO_work_related', $msFindings->TO_work_related ?? '') === 'No' ? 'checked' : ''; ?>></td></tr><tr><th>BEI determinant (BM/BEM) [K]</th><td class="choice-cell"><input type="radio" name="biological_monitoring" value="Yes" <?php echo old('biological_monitoring', $msFindings->biological_monitoring ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="biological_monitoring" value="No" <?php echo old('biological_monitoring', $msFindings->biological_monitoring ?? '') === 'No' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="BM_work_related" value="Yes" <?php echo old('BM_work_related', $msFindings->BM_work_related ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="BM_work_related" value="No" <?php echo old('BM_work_related', $msFindings->BM_work_related ?? '') === 'No' ? 'checked' : ''; ?>></td></tr><tr><th>Pregnancy / Breastfeeding</th><td class="choice-cell"><input type="radio" name="pregnancy_breastFeding" value="Yes" <?php echo old('pregnancy_breastFeding', $msFindings->pregnancy_breastFeding ?? '') === 'Yes' ? 'checked' : ''; ?>></td><td class="choice-cell"><input type="radio" name="pregnancy_breastFeding" value="No" <?php echo old('pregnancy_breastFeding', $msFindings->pregnancy_breastFeding ?? '') === 'No' ? 'checked' : ''; ?>></td><td class="na-cell" colspan="2">Not applicable</td></tr></tbody></table></div><div class="fit-row"><strong>Conclusion of fitness to work</strong><label><input type="radio" name="conclusion_fitness" value="Fit" <?php echo old('conclusion_fitness', $msFindings->conclusion_fitness ?? '') === 'Fit' ? 'checked' : ''; ?>> Fit</label><label><input type="radio" name="conclusion_fitness" value="Not Fit" <?php echo old('conclusion_fitness', $msFindings->conclusion_fitness ?? '') === 'Not Fit' ? 'checked' : ''; ?>> Not Fit</label></div></section>
<section class="card" data-section-index="8" id="section-recommendation"><?php $done = !empty($sectionStatuses['recommendation']); ?><div class="card-head"><div><h3>Recommendation</h3></div><span class="badge <?php echo $done ? 'done' : 'missing'; ?>"><?php echo $done ? 'Completed' : 'Incomplete'; ?></span></div><div class="grid"><div class="field"><label>Recommendation Type</label><input type="text" name="recommencation_type" value="<?php echo $esc(old('recommencation_type', $recommendationData->recommencation_type ?? '')); ?>"></div><div class="field"><label>MRP Start Date</label><input type="date" name="MRPdate_start" value="<?php echo $esc(old('MRPdate_start', $recommendationData->MRPdate_start ?? '')); ?>"></div><div class="field"><label>MRP End Date</label><input type="date" name="MRPdate_end" value="<?php echo $esc(old('MRPdate_end', $recommendationData->MRPdate_end ?? '')); ?>"></div><div class="field"><label>Next Review Date</label><input type="date" name="nextReview_date" value="<?php echo $esc(old('nextReview_date', $recommendationData->nextReview_date ?? '')); ?>"></div><div class="field full"><label>Notes</label><textarea name="notes"><?php echo $esc(old('notes', $recommendationData->notes ?? '')); ?></textarea></div></div></section>
</div><div class="actions"><div id="examWizardText">Section 1 of 9</div><div><a class="btn" id="examPrevLink" href="<?php echo $esc($stepBack); ?>">Back</a> <button class="btn" id="examPrevBtn" type="button" style="display:none;">Previous Section</button> <button class="next" id="examNextBtn" type="button" <?php echo $isReadOnly ? 'style="display:none;"' : ''; ?>>Next Section</button> <button class="next" id="examSaveBtn" type="submit" style="display:none;">Save & Next</button></div></div></form></section></div></div><script>(function(){
var cards=Array.prototype.slice.call(document.querySelectorAll('.card[data-section-index]'));
var navItems=Array.prototype.slice.call(document.querySelectorAll('.status-item'));
var prevBtn=document.getElementById('examPrevBtn');
var nextBtn=document.getElementById('examNextBtn');
var saveBtn=document.getElementById('examSaveBtn');
var prevLink=document.getElementById('examPrevLink');
var text=document.getElementById('examWizardText');
var form=document.getElementById('surveillanceExamForm');
var addBioRowBtn=document.getElementById('addBioRow');
var bioTableBody=document.querySelector('#bioMonitoringTable tbody');
var baselineStore=document.getElementById('baselineResultsStore');
var annualStore=document.getElementById('baselineAnnualStore');
var surveillanceIdInput=document.getElementById('surveillanceIdInput');
var declarationIdInput=document.getElementById('declarationIdInput');
var chemicalStoreUrl='<?php echo $esc(route('surveillance.chemical-option.store')); ?>';
var csrfTokenInput=form?form.querySelector('input[name="_token"]'):null;
var chemicalInput=document.getElementById('chemicalSearchInput');
var chemicalValueInput=document.getElementById('chemicalValueInput');
var chemicalTriggerLabel=document.getElementById('chemicalTriggerLabel');
var chemicalDropdown=document.getElementById('chemicalDropdown');
var chemicalOptionsList=document.getElementById('chemicalOptionsList');
var chemicalEmptyState=document.getElementById('chemicalEmptyState');
var chemicalToggleBtn=document.getElementById('toggleChemicalDropdown');
var addChemicalOptionBtn=document.getElementById('addChemicalOption');
var chemicalAddForm=document.getElementById('chemicalAddForm');
var chemicalNewInput=document.getElementById('chemicalNewInput');
var chemicalAddCancel=document.getElementById('chemicalAddCancel');
var chemicalAddSave=document.getElementById('chemicalAddSave');
var sectionKeys=['chemical','history','clinical','physical','target','biological','respirator','findings','recommendation'];
var current=0;
var isSaving=false;
var isReadOnly=form.getAttribute('data-readonly')==='1';
if(!cards.length||!form){return;}
if(isReadOnly){
    Array.prototype.slice.call(form.querySelectorAll('input, select, textarea, button')).forEach(function(element){
        if(!element.name && element.id !== 'examPrevBtn' && element.id !== 'examPrevLink'){ }
        if(element.type === 'hidden'){return;}
        if(element.id === 'examPrevBtn' || element.id === 'examPrevLink'){return;}
        if(element.id === 'examNextBtn' || element.id === 'examSaveBtn' || element.id === 'addBioRow' || element.id === 'toggleChemicalDropdown' || element.id === 'addChemicalOption' || element.id === 'chemicalAddCancel' || element.id === 'chemicalAddSave'){element.style.display='none'; return;}
        if(element.classList && element.classList.contains('bio-remove')){element.style.display='none'; return;}
        if(element.tagName === 'SELECT' || element.type === 'radio' || element.type === 'checkbox'){element.disabled=true; return;}
        element.readOnly=true;
    });
}
function sync(){cards.forEach(function(card,index){card.classList.toggle('is-active',index===current);});navItems.forEach(function(item,index){item.classList.toggle('is-current',index===current);});if(prevBtn){prevBtn.style.display=current>0?'inline-flex':'none';}if(prevLink){prevLink.style.display=current===0?'inline-flex':'none';}if(nextBtn){nextBtn.style.display=current<cards.length-1?'inline-flex':'none';}if(saveBtn){saveBtn.style.display=current===cards.length-1?'inline-flex':'none';}if(text){text.textContent='Section '+(current+1)+' of '+cards.length;}cards[current].scrollIntoView({behavior:'smooth',block:'start'});} 
function setSectionStatus(index, done){var item=navItems[index];var card=cards[index];if(item){var icon=item.querySelector('.status-icon');var label=item.querySelector('.status-text span');if(icon){icon.classList.remove('ok','bad');icon.classList.add(done?'ok':'bad');icon.innerHTML=done?'&#10003;':'!';}if(label){label.textContent=done?'Completed':'Incomplete';}}if(card){var badge=card.querySelector('.badge');if(badge){badge.classList.remove('done','missing');badge.classList.add(done?'done':'missing');badge.textContent=done?'Completed':'Incomplete';}}}
function updateSectionStatuses(sectionStatuses){if(!sectionStatuses){return;}sectionKeys.forEach(function(key,index){setSectionStatus(index,!!sectionStatuses[key]);});}
function fieldValue(selector){var element=form.querySelector(selector);if(!element){return '';}return (element.value||'').trim();}
function radioValue(name){var checked=form.querySelector('input[name="'+name+'"]:checked');return checked?(checked.value||'').trim():'';}
function everyFilled(names, resolver){return names.every(function(name){var value=resolver(name);return value!=='';});}
function computeSectionCompletion(index){switch(index){case 0:return fieldValue('input[name="company_name"]')!==''&&fieldValue('input[name="chemicals"]')!==''&&fieldValue('select[name="examination_type"]')!==''&&fieldValue('input[name="examination_date"]')!=='';case 1:return everyFilled(['breathing_difficulty','cough','sore_throat','sneezing','chest_pain','palpitation','limb_oedema','drowsiness','dizziness','headache','confusion','lethargy','nausea','vomiting','eye_irritations','blurred_vision','blisters','burns','itching','rash','redness','abdominal_pain','history_abdominal_mass','history_jaundice','diarrhoea','loss_of_weight','loss_of_appetite','dysuria','haematuria'],radioValue);case 2:var clinicalResult=fieldValue('select[name="result_clinical_findings"]');return clinicalResult!==''&&(clinicalResult!=='Yes'||fieldValue('textarea[name="elaboration"]')!=='');case 3:return fieldValue('input[name="weight"]')!==''&&fieldValue('input[name="height"]')!==''&&fieldValue('input[name="BMI"]')!==''&&fieldValue('input[name="bp_systolic"]')!==''&&fieldValue('input[name="bp_distolic"]')!==''&&fieldValue('input[name="pulse_rate"]')!==''&&fieldValue('input[name="respiratory_rate"]')!==''&&fieldValue('textarea[name="general_appearances"]')!==''&&everyFilled(['s1_s2','murmur','ear_nose_throat','visual_acuity_right','visual_acuity_left','colour_blindness','gas_tenderness','abdominal_mass','lymph_nodes','splenomegaly','kidney_tenderness','ballotable','jaundice','hepatomegaly','muscle_tone','muscle_tenderness','power','sensation','sound','air_entry','reproductive','skin'],function(name){var el=form.querySelector('[name="'+name+'"]');return el?(el.value||'').trim():'';});case 4:return everyFilled(['blood_count','renal_function','liver_function','chest_xray'],radioValue)&&fieldValue('input[name="spirometry_FEV1"]')!==''&&fieldValue('input[name="spirometry_FVC"]')!==''&&fieldValue('input[name="spirometry_FEV_FVC"]')!=='';case 5:buildBioPayload();var baselineLines=(baselineStore&&baselineStore.value?baselineStore.value.split(/\r\n|\r|\n/):[]).filter(function(line){return line.trim()!=='';});var annualLines=(annualStore&&annualStore.value?annualStore.value.split(/\r\n|\r|\n/):[]).filter(function(line){return line.trim()!=='';});if(!baselineLines.length||baselineLines.length!==annualLines.length){return false;}return baselineLines.every(function(line,idx){var parts=line.split('::');return (parts[0]||'').trim()!==''&&(parts[1]||'').trim()!==''&&(annualLines[idx]||'').trim()!=='';});case 6:var fitnessResult=radioValue('fitness_result');return fitnessResult!==''&&(fitnessResult!=='Not fit'||fieldValue('textarea[name="fitness_justification"]')!=='');case 7:return everyFilled(['history_of_health','clinical_findings','CF_work_related','target_organ','TO_work_related','biological_monitoring','BM_work_related','pregnancy_breastFeding','conclusion_fitness'],radioValue);case 8:return fieldValue('input[name="recommencation_type"]')!==''&&fieldValue('input[name="MRPdate_start"]')!==''&&fieldValue('input[name="MRPdate_end"]')!==''&&fieldValue('input[name="nextReview_date"]')!=='';default:return false;}}
function refreshVisibleStatuses(){sectionKeys.forEach(function(key,index){setSectionStatus(index,computeSectionCompletion(index));});}
function refreshBioRemoveButtons(){if(!bioTableBody){return;}var rows=bioTableBody.querySelectorAll('.bio-row');rows.forEach(function(row){var btn=row.querySelector('.bio-remove');if(btn){btn.style.visibility=rows.length>1?'visible':'hidden';}});} 
function buildBioPayload(){if(!bioTableBody||!baselineStore||!annualStore){return;}var baselineLines=[];var annualLines=[];bioTableBody.querySelectorAll('.bio-row').forEach(function(row){var determinant=(row.querySelector('.bio-determinant')||{}).value||'';var baseline=(row.querySelector('.bio-baseline')||{}).value||'';var annual=(row.querySelector('.bio-annual')||{}).value||'';if(determinant.trim()||baseline.trim()||annual.trim()){baselineLines.push(determinant.trim()+'::'+baseline.trim());annualLines.push(annual.trim());}});baselineStore.value=baselineLines.join('\n');annualStore.value=annualLines.join('\n');}
function persistExamData(){buildBioPayload();var payload=new FormData(form);payload.set('autosave','1');isSaving=true;if(nextBtn){nextBtn.disabled=true;}return fetch(form.getAttribute('action'),{method:'POST',headers:{'X-Requested-With':'XMLHttpRequest','Accept':'application/json','X-CSRF-TOKEN':csrfTokenInput?csrfTokenInput.value:''},body:payload}).then(function(response){if(!response.ok){throw new Error('Unable to save examination');}return response.json();}).then(function(data){if(surveillanceIdInput&&data.surveillance_id){surveillanceIdInput.value=data.surveillance_id;}if(declarationIdInput&&data.declaration_id){declarationIdInput.value=data.declaration_id;}updateSectionStatuses(data.sectionStatuses||{});return data;}).finally(function(){isSaving=false;if(nextBtn){nextBtn.disabled=false;}});}
if(addBioRowBtn&&bioTableBody){addBioRowBtn.addEventListener('click',function(){var row=document.createElement('tr');row.className='bio-row';row.innerHTML='<td class="text-cell"><input type="text" class="bio-determinant" placeholder="Determinant / test name"></td><td class="text-cell"><input type="text" class="bio-baseline" placeholder="Baseline result"></td><td class="text-cell"><input type="text" class="bio-annual" placeholder="Annual result"></td><td class="choice-cell"><button type="button" class="small-btn bio-remove" style="padding:8px 12px;min-width:44px;">&#8855;</button></td>';bioTableBody.appendChild(row);refreshBioRemoveButtons();});bioTableBody.addEventListener('click',function(event){var btn=event.target.closest('.bio-remove');if(!btn){return;}var rows=bioTableBody.querySelectorAll('.bio-row');if(rows.length<=1){return;}btn.closest('.bio-row').remove();refreshBioRemoveButtons();});refreshBioRemoveButtons();}
function chemicalOptions(){return chemicalOptionsList?Array.prototype.slice.call(chemicalOptionsList.querySelectorAll('[data-chemical-option]')):[];}
function updateChemicalTrigger(value){if(!chemicalTriggerLabel||!chemicalToggleBtn){return;}var hasValue=(value||'').trim()!=='';chemicalTriggerLabel.textContent=hasValue?value:'Select chemical';chemicalToggleBtn.classList.toggle('is-placeholder',!hasValue);chemicalToggleBtn.setAttribute('aria-expanded',chemicalDropdown&&chemicalDropdown.classList.contains('is-open')?'true':'false');}
function filterChemicalOptions(){if(!chemicalInput){return;}var query=(chemicalInput.value||'').trim().toLowerCase();var visibleCount=0;chemicalOptions().forEach(function(option){var optionText=(option.getAttribute('data-chemical-option')||'').toLowerCase();var match=query===''||optionText.indexOf(query)!==-1;option.style.display=match?'':'none';if(match){visibleCount+=1;}});if(chemicalEmptyState){chemicalEmptyState.style.display=visibleCount===0?'':'none';}}
function openChemicalDropdown(){if(!chemicalDropdown){return;}chemicalDropdown.classList.add('is-open');filterChemicalOptions();updateChemicalTrigger(chemicalValueInput?chemicalValueInput.value:'');if(chemicalInput){chemicalInput.value=chemicalValueInput?chemicalValueInput.value:'';chemicalInput.focus();}}
function closeChemicalDropdown(){if(!chemicalDropdown){return;}chemicalDropdown.classList.remove('is-open');hideChemicalAddForm();updateChemicalTrigger(chemicalValueInput?chemicalValueInput.value:'');}
function selectChemicalOption(value){if(chemicalValueInput){chemicalValueInput.value=value;}if(chemicalInput){chemicalInput.value=value;}updateChemicalTrigger(value);closeChemicalDropdown();}
function appendChemicalOption(value){if(!chemicalOptionsList){return;}var existing=chemicalOptions().find(function(option){return (option.getAttribute('data-chemical-option')||'').toLowerCase()===value.toLowerCase();});if(existing){return existing;}var option=document.createElement('div');option.className='chemical-option';option.setAttribute('data-chemical-option',value);option.setAttribute('role','option');option.textContent=value;chemicalOptionsList.insertBefore(option, chemicalEmptyState || null);return option;}
function showChemicalAddForm(){if(!chemicalAddForm){return;}chemicalAddForm.style.display='grid';if(chemicalNewInput){chemicalNewInput.value=chemicalInput?chemicalInput.value:'';chemicalNewInput.focus();}}
function hideChemicalAddForm(){if(!chemicalAddForm){return;}chemicalAddForm.style.display='none';if(chemicalNewInput){chemicalNewInput.value='';}}
function addChemicalOption(valueOverride){if(!chemicalOptionsList){return Promise.resolve();}var value=(valueOverride!==undefined?valueOverride:(chemicalNewInput?chemicalNewInput.value:chemicalInput?chemicalInput.value:'')).trim();if(!value){return Promise.resolve();}appendChemicalOption(value);if(!chemicalStoreUrl||!window.fetch){selectChemicalOption(value);hideChemicalAddForm();return Promise.resolve();}return fetch(chemicalStoreUrl,{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':csrfTokenInput?csrfTokenInput.value:'','Accept':'application/json'},body:JSON.stringify({chemical_name:value})}).then(function(response){if(!response.ok){throw new Error('Unable to save chemical');}return response.json();}).then(function(payload){var savedValue=(payload&&payload.chemical_name)?payload.chemical_name:value;appendChemicalOption(savedValue);selectChemicalOption(savedValue);hideChemicalAddForm();}).catch(function(){selectChemicalOption(value);hideChemicalAddForm();});}
updateChemicalTrigger(chemicalValueInput?chemicalValueInput.value:'');
if(addChemicalOptionBtn){addChemicalOptionBtn.addEventListener('click',function(){showChemicalAddForm();});}
if(chemicalAddCancel){chemicalAddCancel.addEventListener('click',function(){hideChemicalAddForm();});}
if(chemicalAddSave){chemicalAddSave.addEventListener('click',function(){addChemicalOption();});}
if(chemicalToggleBtn){chemicalToggleBtn.addEventListener('click',function(){if(!chemicalDropdown){return;}if(chemicalDropdown.classList.contains('is-open')){closeChemicalDropdown();return;}openChemicalDropdown();});}
if(chemicalInput){chemicalInput.addEventListener('input',filterChemicalOptions);chemicalInput.addEventListener('keydown',function(event){if(event.key==='Escape'){closeChemicalDropdown();}});}
if(chemicalNewInput){chemicalNewInput.addEventListener('keydown',function(event){if(event.key==='Enter'){event.preventDefault();addChemicalOption();}if(event.key==='Escape'){hideChemicalAddForm();}});}
if(chemicalDropdown){chemicalDropdown.addEventListener('click',function(event){var option=event.target.closest('[data-chemical-option]');if(!option){return;}selectChemicalOption(option.getAttribute('data-chemical-option')||option.textContent||'');});document.addEventListener('click',function(event){if(!chemicalDropdown.contains(event.target)&&event.target!==chemicalToggleBtn){closeChemicalDropdown();}});} 
if(form){form.addEventListener('submit',function(){buildBioPayload();});}
if(prevBtn){prevBtn.addEventListener('click',function(){if(current>0){current-=1;sync();}});}
if(nextBtn){nextBtn.addEventListener('click',function(){if(current>=cards.length-1){return;}if(isReadOnly){current+=1;sync();return;}if(isSaving){return;}persistExamData().then(function(){current+=1;sync();}).catch(function(){current+=1;sync();});});}
refreshVisibleStatuses();
if(form){form.addEventListener('input',refreshVisibleStatuses);form.addEventListener('change',refreshVisibleStatuses);}
sync();
})();</script><?php medis_render_navigation_end(); ?>
</body></html>
























































